const { cache, normalizeQuery } = require('./src/query-cache');

let passed = 0;
let failed = 0;

function assert(condition, msg) {
  if (condition) { console.log(`  ✅ ${msg}`); passed++; }
  else { console.log(`  ❌ ${msg}`); failed++; process.exitCode = 1; }
}

// Test 1: set/get
console.log('Test 1: Cache set/get');
cache.clear(); cache.resetStats();
cache.set('implementare checkout', { result: 'checkout-data' });
const hit = cache.get('implementare checkout');
assert(hit && hit.result === 'checkout-data', 'set/get works');

// Test 2: case-insensitive via normalizeQuery in get/set/has
console.log('\nTest 2: Case-insensitive normalization');
cache.clear(); cache.resetStats();
cache.set('Implementare Checkout', { result: 'data1' });
const h = cache.get('implementare checkout');
assert(h && h.result === 'data1', 'case-insensitive get works');

// Test 3: normalizeQuery function
console.log('\nTest 3: normalizeQuery');
const n1 = normalizeQuery('Implementare Checkout');
assert(n1 === 'implementare checkout', `lowercase: "Implementare Checkout" → "${n1}"`);

const n2 = normalizeQuery('the is a query for results');
assert(n2 === 'query results', `EN stopword removal: "${n2}"`);

const n3 = normalizeQuery('cerca nel database i documenti della sezione');
console.log(`  ℹ️ IT stopwords: "cerca nel database..." → "${n3}"`);

// Test 4: stats tracking
console.log('\nTest 4: Stats tracking');
cache.clear(); cache.resetStats();
cache.set('k', 'v1');
cache.get('k');       // hit
cache.get('non-esiste'); // miss
const s = cache.getStats();
assert(s.hits >= 1, `hits=${s.hits}`);
assert(s.misses >= 1, `misses=${s.misses}`);

// Test 5: has() without TTL update
console.log('\nTest 5: has() does not refresh TTL');
cache.clear(); cache.resetStats();
cache.set('ttl-test', 'value');
const before = Date.now();
cache.has('ttl-test'); // should NOT refresh TTL
assert(cache.get('ttl-test') === 'value', 'has() + get() returns value');

// Test 6: clear()
console.log('\nTest 6: clear()');
cache.clear(); cache.resetStats();
cache.set('a', 1); cache.set('b', 2);
assert(cache.get('a') === undefined, 'clear removes all entries');
assert(cache.get('b') === undefined, 'clear removes all entries (second)');

// Test 7: Symbol boost integration check
console.log('\nTest 7: Symbol boost in pipeline');
const { applySymbolBoost } = require('./src/re-ranking');
const results = [
  { score: 0.5, payload: { symbolNames: ['buildCodeText'] }, text: 'test1' },
  { score: 0.8, payload: { symbolNames: ['otherFunc'] }, text: 'test2' }
];
applySymbolBoost(results, 'implementare build');
assert(results[0].score === 0.75, `symbol boost applied: ${results[0].score} (expected 0.75)`);

// Test 8: extractTokens filters stopwords and short tokens
console.log('\nTest 8: extractTokens');
const { extractTokens } = require('./src/re-ranking');
const tokens = extractTokens('the is a query for buildCodeText');
assert(!tokens.includes('the'), 'stopword "the" filtered out');
assert(tokens.some(t => t.includes('build')), 'significant token preserved');

console.log(`\n=== RESULTS: ${passed} passed, ${failed} failed ===`);

